import React, { useState, useMemo, useRef, useEffect } from 'react';

// ============================================
// Design Tokens
// ============================================
const theme = {
  colors: {
    primary: '#8b5cf6',
    background: '#0a0a0a',
    surface: '#141414',
    surfaceAlt: '#1a1a1a',
    border: '#262626',
    text: '#fafafa',
    textSecondary: '#a1a1aa',
    textMuted: '#52525b',
    positive: '#10b981',
    negative: '#f43f5e',
    accent1: '#f472b6',
    accent2: '#38bdf8',
    accent3: '#a3e635',
  },
  font: "'JetBrains Mono', monospace",
};

const sampleColors = ['#f472b6', '#38bdf8', '#a3e635', '#fbbf24', '#a78bfa', '#fb7185'];

// ============================================
// Main Visualization - Connected Scatter
// ============================================
function RelationshipViz({ data, features, featureX, featureY, means }) {
  const canvasRef = useRef(null);
  const size = 380;
  const padding = 50;

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');

    // Clear
    ctx.fillStyle = theme.colors.surface;
    ctx.fillRect(0, 0, size, size);

    if (featureX < 0 || featureY < 0) return;

    const xVals = data[featureX];
    const yVals = data[featureY];
    const meanX = means[featureX];
    const meanY = means[featureY];
    const n = xVals.length;

    // Compute covariance for trend
    let cov = 0;
    for (let i = 0; i < n; i++) {
      cov += (xVals[i] - meanX) * (yVals[i] - meanY);
    }
    cov /= (n - 1);

    // Scaling
    const allX = [...xVals, meanX];
    const allY = [...yVals, meanY];
    const xMin = Math.min(...allX) - 1;
    const xMax = Math.max(...allX) + 1;
    const yMin = Math.min(...allY) - 1;
    const yMax = Math.max(...allY) + 1;

    const scaleX = (v) => padding + ((v - xMin) / (xMax - xMin)) * (size - 2 * padding);
    const scaleY = (v) => size - padding - ((v - yMin) / (yMax - yMin)) * (size - 2 * padding);

    const meanXc = scaleX(meanX);
    const meanYc = scaleY(meanY);

    // Subtle quadrant shading
    ctx.globalAlpha = 0.06;
    ctx.fillStyle = theme.colors.positive;
    ctx.fillRect(meanXc, padding, size - padding - meanXc, meanYc - padding);
    ctx.fillRect(padding, meanYc, meanXc - padding, size - padding - meanYc);
    ctx.fillStyle = theme.colors.negative;
    ctx.fillRect(padding, padding, meanXc - padding, meanYc - padding);
    ctx.fillRect(meanXc, meanYc, size - padding - meanXc, size - padding - meanYc);
    ctx.globalAlpha = 1;

    // Grid
    ctx.strokeStyle = theme.colors.border;
    ctx.lineWidth = 1;
    for (let i = 0; i <= 5; i++) {
      const pos = padding + (i / 5) * (size - 2 * padding);
      ctx.beginPath();
      ctx.moveTo(pos, padding);
      ctx.lineTo(pos, size - padding);
      ctx.stroke();
      ctx.beginPath();
      ctx.moveTo(padding, pos);
      ctx.lineTo(size - padding, pos);
      ctx.stroke();
    }

    // Mean lines
    ctx.strokeStyle = theme.colors.textMuted;
    ctx.lineWidth = 2;
    ctx.setLineDash([8, 6]);
    ctx.beginPath();
    ctx.moveTo(meanXc, padding);
    ctx.lineTo(meanXc, size - padding);
    ctx.stroke();
    ctx.beginPath();
    ctx.moveTo(padding, meanYc);
    ctx.lineTo(size - padding, meanYc);
    ctx.stroke();
    ctx.setLineDash([]);

    // Mean intersection
    ctx.fillStyle = theme.colors.textMuted;
    ctx.beginPath();
    ctx.arc(meanXc, meanYc, 6, 0, Math.PI * 2);
    ctx.fill();

    // Draw points with glow
    xVals.forEach((x, i) => {
      const y = yVals[i];
      const cx = scaleX(x);
      const cy = scaleY(y);

      const devX = x - meanX;
      const devY = y - meanY;
      const contribution = devX * devY;
      const isPositive = contribution >= 0;

      // Glow
      const gradient = ctx.createRadialGradient(cx, cy, 0, cx, cy, 24);
      gradient.addColorStop(0, isPositive ? 'rgba(16, 185, 129, 0.3)' : 'rgba(244, 63, 94, 0.3)');
      gradient.addColorStop(1, 'transparent');
      ctx.fillStyle = gradient;
      ctx.beginPath();
      ctx.arc(cx, cy, 24, 0, Math.PI * 2);
      ctx.fill();

      // Point
      ctx.fillStyle = sampleColors[i % sampleColors.length];
      ctx.beginPath();
      ctx.arc(cx, cy, 10, 0, Math.PI * 2);
      ctx.fill();

      // Border
      ctx.strokeStyle = theme.colors.surface;
      ctx.lineWidth = 2;
      ctx.stroke();

      // Label
      ctx.fillStyle = theme.colors.text;
      ctx.font = 'bold 11px JetBrains Mono';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText(`${i + 1}`, cx, cy);
    });

    // Axis labels
    ctx.fillStyle = theme.colors.text;
    ctx.font = '13px JetBrains Mono';
    ctx.textAlign = 'center';
    ctx.textBaseline = 'top';
    ctx.fillText(features[featureX], size / 2, size - 18);

    ctx.save();
    ctx.translate(16, size / 2);
    ctx.rotate(-Math.PI / 2);
    ctx.textBaseline = 'middle';
    ctx.fillText(features[featureY], 0, 0);
    ctx.restore();

    // Covariance indicator
    const covColor = cov >= 0 ? theme.colors.positive : theme.colors.negative;
    const covSign = cov >= 0 ? '+' : '';
    ctx.fillStyle = covColor;
    ctx.font = 'bold 14px JetBrains Mono';
    ctx.textAlign = 'right';
    ctx.fillText(`Cov: ${covSign}${cov.toFixed(1)}`, size - padding, padding - 12);

  }, [data, features, featureX, featureY, means]);

  return (
    <canvas
      ref={canvasRef}
      width={size}
      height={size}
      style={{ borderRadius: '12px', display: 'block' }}
    />
  );
}

// ============================================
// Variance Visualization
// ============================================
function VarianceViz({ data, features, featureIdx, mean }) {
  const canvasRef = useRef(null);
  const size = 380;

  useEffect(() => {
    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');

    ctx.fillStyle = theme.colors.surface;
    ctx.fillRect(0, 0, size, size);

    if (featureIdx < 0) return;

    const vals = data[featureIdx];
    const n = vals.length;

    // Compute variance
    let variance = 0;
    for (let i = 0; i < n; i++) {
      variance += Math.pow(vals[i] - mean, 2);
    }
    variance /= (n - 1);

    const padding = 60;
    const centerY = size / 2;
    const minVal = Math.min(...vals, mean) - 2;
    const maxVal = Math.max(...vals, mean) + 2;

    const scaleX = (v) => padding + ((v - minVal) / (maxVal - minVal)) * (size - 2 * padding);
    const meanXc = scaleX(mean);

    // Number line
    ctx.strokeStyle = theme.colors.border;
    ctx.lineWidth = 3;
    ctx.lineCap = 'round';
    ctx.beginPath();
    ctx.moveTo(padding, centerY);
    ctx.lineTo(size - padding, centerY);
    ctx.stroke();

    // Tick marks
    ctx.fillStyle = theme.colors.textMuted;
    ctx.font = '10px JetBrains Mono';
    ctx.textAlign = 'center';
    for (let v = Math.ceil(minVal); v <= Math.floor(maxVal); v++) {
      const x = scaleX(v);
      ctx.beginPath();
      ctx.moveTo(x, centerY - 6);
      ctx.lineTo(x, centerY + 6);
      ctx.stroke();
      ctx.fillText(v.toString(), x, centerY + 22);
    }

    // Mean marker
    ctx.fillStyle = theme.colors.primary;
    ctx.beginPath();
    ctx.moveTo(meanXc, centerY - 20);
    ctx.lineTo(meanXc - 8, centerY - 35);
    ctx.lineTo(meanXc + 8, centerY - 35);
    ctx.closePath();
    ctx.fill();

    ctx.font = 'bold 11px JetBrains Mono';
    ctx.fillText(`μ = ${mean.toFixed(1)}`, meanXc, centerY - 45);

    // Draw spread lines from mean to each point
    vals.forEach((v, i) => {
      const x = scaleX(v);
      const yOffset = (i - (n - 1) / 2) * 30;
      const pointY = centerY + 60 + yOffset;

      // Connection line
      ctx.strokeStyle = `${sampleColors[i]}60`;
      ctx.lineWidth = 2;
      ctx.beginPath();
      ctx.moveTo(meanXc, centerY);
      ctx.lineTo(x, pointY);
      ctx.stroke();

      // Horizontal deviation line
      ctx.strokeStyle = sampleColors[i];
      ctx.lineWidth = 3;
      ctx.beginPath();
      ctx.moveTo(meanXc, pointY);
      ctx.lineTo(x, pointY);
      ctx.stroke();

      // Point
      ctx.fillStyle = sampleColors[i];
      ctx.beginPath();
      ctx.arc(x, pointY, 12, 0, Math.PI * 2);
      ctx.fill();

      ctx.fillStyle = theme.colors.surface;
      ctx.font = 'bold 11px JetBrains Mono';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText(`${i + 1}`, x, pointY);

      // Deviation label
      const dev = v - mean;
      ctx.fillStyle = theme.colors.textSecondary;
      ctx.font = '10px JetBrains Mono';
      ctx.fillText(`${dev >= 0 ? '+' : ''}${dev.toFixed(1)}`, (meanXc + x) / 2, pointY - 18);
    });

    // Feature label
    ctx.fillStyle = theme.colors.text;
    ctx.font = '14px JetBrains Mono';
    ctx.textAlign = 'center';
    ctx.fillText(features[featureIdx], size / 2, 30);

    // Variance
    ctx.fillStyle = theme.colors.primary;
    ctx.font = 'bold 13px JetBrains Mono';
    ctx.fillText(`Variance: ${variance.toFixed(1)}`, size / 2, size - 25);

  }, [data, features, featureIdx, mean]);

  return (
    <canvas
      ref={canvasRef}
      width={size}
      height={size}
      style={{ borderRadius: '12px', display: 'block' }}
    />
  );
}

