function CovMatrixMini({ matrix, features, highlightCell, revealedCells }) {
  return (
    <div style={{
      display: 'inline-flex',
      flexDirection: 'column',
      gap: '4px',
      padding: '12px',
      background: theme.colors.surfaceAlt,
      borderRadius: '12px',
    }}>
      {/* Header */}
      <div style={{ display: 'flex', gap: '4px', marginLeft: '44px' }}>
        {features.map((f, j) => (
          <div key={j} style={{
            width: '44px',
            textAlign: 'center',
            fontSize: '9px',
            color: theme.colors.textMuted,
            fontWeight: '600',
          }}>
            {f.slice(0, 4)}
          </div>
        ))}
      </div>

      {matrix.map((row, i) => (
        <div key={i} style={{ display: 'flex', alignItems: 'center', gap: '4px' }}>
          <div style={{
            width: '40px',
            textAlign: 'right',
            fontSize: '9px',
            color: theme.colors.textMuted,
            fontWeight: '600',
          }}>
            {features[i].slice(0, 4)}
          </div>
          {row.map((val, j) => {
            const isHighlighted = highlightCell?.i === i && highlightCell?.j === j;
            const isRevealed = !revealedCells || revealedCells.some(c => c.i === i && c.j === j);
            const isDiag = i === j;

            let bg = theme.colors.background;
            let color = theme.colors.textMuted;

            if (isRevealed) {
              if (val > 0.1) color = theme.colors.positive;
              else if (val < -0.1) color = theme.colors.negative;
              else color = theme.colors.textSecondary;
            }

            if (isHighlighted) {
              bg = theme.colors.primary;
              color = theme.colors.surface;
            } else if (isDiag && isRevealed) {
              bg = `${theme.colors.primary}20`;
            }

            return (
              <div
                key={j}
                style={{
                  width: '44px',
                  height: '32px',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  background: bg,
                  borderRadius: '6px',
                  color,
                  fontSize: '11px',
                  fontWeight: '600',
                  transition: 'all 0.2s',
                  transform: isHighlighted ? 'scale(1.1)' : 'scale(1)',
                }}
              >
                {isRevealed ? val.toFixed(1) : '?'}
              </div>
            );
          })}
        </div>
      ))}
    </div>
  );
}

