export default function CovariancePlayground() {
  const [exampleIdx, setExampleIdx] = useState(0);
  const [step, setStep] = useState(0);
  const [playing, setPlaying] = useState(false);

  const examples = [
    {
      name: 'Students',
      icon: '🎓',
      features: ['Study', 'Sleep', 'Grade'],
      data: [[2, 4, 6, 8], [8, 7, 5, 4], [55, 70, 80, 95]],
      insights: {
        '0-0': { text: 'Students vary in study habits — some cram, others coast.', type: 'neutral' },
        '0-1': { text: 'More study = less sleep. The classic student tradeoff!', type: 'negative' },
        '0-2': { text: 'Study pays off! More hours studying = better grades.', type: 'positive' },
        '1-1': { text: 'Sleep varies — night owls vs early birds.', type: 'neutral' },
        '1-2': { text: 'Less sleep = higher grades... but at what cost?', type: 'negative' },
        '2-2': { text: 'Grades are spread out — a mix of strugglers and stars.', type: 'neutral' },
      },
    },
    {
      name: 'Houses',
      icon: '🏠',
      features: ['SqFt', 'Beds', 'Price'],
      data: [[1200, 1600, 2000, 2800], [2, 3, 3, 5], [180, 260, 320, 480]],
      insights: {
        '0-0': { text: 'Houses range from cozy apartments to spacious homes.', type: 'neutral' },
        '0-1': { text: 'Bigger houses have more bedrooms. Makes sense!', type: 'positive' },
        '0-2': { text: 'Size matters for price — every square foot counts!', type: 'positive' },
        '1-1': { text: 'Bedroom count varies from 2 to 5.', type: 'neutral' },
        '1-2': { text: 'More bedrooms = higher price tag.', type: 'positive' },
        '2-2': { text: 'Prices range widely in this market.', type: 'neutral' },
      },
    },
    {
      name: 'Weather',
      icon: '☀️',
      features: ['Temp', 'Sales', 'Rain'],
      data: [[55, 70, 85, 95], [80, 180, 320, 400], [4, 2, 0, 0]],
      insights: {
        '0-0': { text: 'Temperature swings from chilly to scorching.', type: 'neutral' },
        '0-1': { text: 'Hot days = ice cream bonanza! Sales soar with temp.', type: 'positive' },
        '0-2': { text: 'Hot days are dry days — less rain when its warm.', type: 'negative' },
        '1-1': { text: 'Sales vary wildly based on conditions.', type: 'neutral' },
        '1-2': { text: 'Rain kills sales — who wants ice cream in a storm?', type: 'negative' },
        '2-2': { text: 'Some days are soggy, others bone dry.', type: 'neutral' },
      },
    },
  ];

  const ex = examples[exampleIdx];
  const nFeatures = ex.features.length;
  const totalSteps = (nFeatures * (nFeatures + 1)) / 2;

  const means = useMemo(() => 
    ex.data.map(f => f.reduce((a, b) => a + b, 0) / f.length),
    [ex.data]
  );

  const covMatrix = useMemo(() => {
    const n = ex.data[0].length;
    const mat = ex.features.map(() => ex.features.map(() => 0));
    for (let i = 0; i < nFeatures; i++) {
      for (let j = 0; j < nFeatures; j++) {
        let sum = 0;
        for (let k = 0; k < n; k++) {
          sum += (ex.data[i][k] - means[i]) * (ex.data[j][k] - means[j]);
        }
        mat[i][j] = sum / (n - 1);
      }
    }
    return mat;
  }, [ex, means, nFeatures]);

  const stepInfo = useMemo(() => {
    if (step === 0) return null;
    let s = 0;
    for (let i = 0; i < nFeatures; i++) {
      for (let j = i; j < nFeatures; j++) {
        s++;
        if (s === step) return { i, j };
      }
    }
    return null;
  }, [step, nFeatures]);

  const revealed = useMemo(() => {
    const cells = [];
    let s = 0;
    for (let i = 0; i < nFeatures; i++) {
      for (let j = i; j < nFeatures; j++) {
        s++;
        if (s <= step) {
          cells.push({ i, j });
          if (i !== j) cells.push({ i: j, j: i });
        }
      }
    }
    return cells;
  }, [step, nFeatures]);

  const reset = () => { setStep(0); setPlaying(false); };
  const next = () => step < totalSteps && setStep(step + 1);
  const prev = () => step > 0 && setStep(step - 1);
  const auto = async () => {
    setPlaying(true);
    for (let s = step; s < totalSteps; s++) {
      setStep(s + 1);
      await new Promise(r => setTimeout(r, 1200));
    }
    setPlaying(false);
  };

  const isDiag = stepInfo?.i === stepInfo?.j;
  const insightKey = stepInfo ? `${stepInfo.i}-${stepInfo.j}` : null;
  const insight = insightKey ? ex.insights[insightKey] : null;

  return (
    <div style={{
      minHeight: '100vh',
      background: theme.colors.background,
      color: theme.colors.text,
      fontFamily: theme.font,
      padding: '24px',
    }}>
      <div style={{ maxWidth: '900px', margin: '0 auto' }}>
        {/* Header */}
        <div style={{ textAlign: 'center', marginBottom: '20px' }}>
          <h1 style={{ fontSize: '22px', fontWeight: '700', margin: 0, letterSpacing: '-0.5px' }}>
            Covariance Matrix
          </h1>
          <p style={{ color: theme.colors.textSecondary, fontSize: '13px', marginTop: '6px' }}>
            Do these features move together, or pull apart?
          </p>
        </div>

        {/* Example Tabs */}
        <div style={{ display: 'flex', gap: '10px', justifyContent: 'center', marginBottom: '20px' }}>
          {examples.map((e, idx) => (
            <button
              key={idx}
              onClick={() => { setExampleIdx(idx); reset(); }}
              style={{
                padding: '10px 20px',
                background: exampleIdx === idx ? theme.colors.primary : theme.colors.surface,
                border: `1px solid ${exampleIdx === idx ? theme.colors.primary : theme.colors.border}`,
                borderRadius: '10px',
                color: exampleIdx === idx ? '#fff' : theme.colors.textSecondary,
                fontFamily: theme.font,
                fontSize: '13px',
                fontWeight: '500',
                cursor: 'pointer',
                display: 'flex',
                alignItems: 'center',
                gap: '6px',
              }}
            >
              <span>{e.icon}</span> {e.name}
            </button>
          ))}
        </div>

        {/* Sample Cards */}
        <div style={{
          background: theme.colors.surface,
          borderRadius: '16px',
          padding: '20px',
          marginBottom: '16px',
        }}>
          <div style={{
            fontSize: '11px',
            color: theme.colors.textMuted,
            textTransform: 'uppercase',
            letterSpacing: '1px',
            marginBottom: '12px',
            textAlign: 'center',
          }}>
            Sample Data
          </div>
          <SampleCards data={ex.data} features={ex.features} highlightPair={stepInfo} />
        </div>

        {/* Main Content */}
        <div style={{
          background: theme.colors.surface,
          borderRadius: '16px',
          padding: '24px',
        }}>
          {step === 0 ? (
            <div style={{ textAlign: 'center', padding: '40px 20px' }}>
              <div style={{ fontSize: '40px', marginBottom: '16px' }}>🔍</div>
              <div style={{ fontSize: '16px', color: theme.colors.text, marginBottom: '8px' }}>
                Ready to explore?
              </div>
              <div style={{ fontSize: '13px', color: theme.colors.textSecondary, maxWidth: '400px', margin: '0 auto' }}>
                Click <strong>Start</strong> to see how {ex.features.join(', ')} relate to each other.
              </div>
            </div>
          ) : (
            <div style={{ display: 'flex', gap: '24px', alignItems: 'flex-start' }}>
              {/* Visualization */}
              <div style={{ flex: 1 }}>
                {isDiag ? (
                  <VarianceViz
                    data={ex.data}
                    features={ex.features}
                    featureIdx={stepInfo.i}
                    mean={means[stepInfo.i]}
                  />
                ) : (
                  <RelationshipViz
                    data={ex.data}
                    features={ex.features}
                    featureX={stepInfo.i}
                    featureY={stepInfo.j}
                    means={means}
                  />
                )}
              </div>

              {/* Matrix */}
              <div>
                <CovMatrixMini
                  matrix={covMatrix}
                  features={ex.features}
                  highlightCell={stepInfo}
                  revealedCells={revealed}
                />
              </div>
            </div>
          )}

          {/* Insight */}
          {insight && (
            <div style={{ marginTop: '20px' }}>
              <InsightBox text={insight.text} type={insight.type} />
            </div>
          )}

          {/* Controls */}
          <div style={{ marginTop: '20px' }}>
            <Controls
              step={step}
              total={totalSteps}
              onPrev={prev}
              onNext={next}
              onReset={reset}
              onAuto={auto}
              playing={playing}
            />
          </div>
        </div>

        {/* Legend */}
        <div style={{
          display: 'flex',
          justifyContent: 'center',
          gap: '24px',
          marginTop: '16px',
          fontSize: '12px',
          color: theme.colors.textSecondary,
        }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
            <div style={{ width: '12px', height: '12px', borderRadius: '3px', background: theme.colors.positive }} />
            Positive (move together)
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
            <div style={{ width: '12px', height: '12px', borderRadius: '3px', background: theme.colors.negative }} />
            Negative (opposite)
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: '6px' }}>
            <div style={{ width: '12px', height: '12px', borderRadius: '3px', background: `${theme.colors.primary}50` }} />
            Diagonal (variance)
          </div>
        </div>
      </div>
    </div>
  );
}

